public class Solution {
    public List<Integer> solve(int n) {
        if (n <= 1) {
            return Arrays.asList(0, 1);
        }
        List<Integer> fib = new ArrayList<>();
        fib.add(0);
        fib.add(1);
        for (int i = 2; i <= n; i++) {
            fib.add(fib.get(i-1) + fib.get(i-2));
        }
        return fib;
    }
}

